mapper.select:
select *,required_class_hour as requiredMinutes
from people_enterprise as s
left join  (
select a.employee_id_number as employee_id_number,sum(a.material_learn_length) as learningMinutes
from (
select distinct employee_id_number,material_id,material_learn_length
from employee_train
where operate_datetime < #{yearEnd} and operate_datetime > #{yearStart} and record_status = 1
) as a
group by a.employee_id_number
) as b on (s.identity_number = b.employee_id_number)
left join (
SELECT
employee_id_number as new_employee_id_number,exam_status
FROM
employee_exam
where id in
(
SELECT
max( id ) AS maxId
FROM
employee_exam
WHERE operate_datetime < #{yearEnd} and operate_datetime > #{yearStart}
GROUP BY employee_id_number
)
) as c on (s.identity_number = c.new_employee_id_number)


        and

            (learningMinutes is null or learningMinutes = 0 or learningMinutes = ' ')


            learningMinutes < required_class_hour and learningMinutes != 0


            learningMinutes >= required_class_hour



        and

            (exam_status is null or exam_status = ' ' or exam_status = 0)


            exam_status = 1


            exam_status = 2



        and town_id in

            #{town}



        and ${searchParam.townId} in

            #{town}

        and town_id = #{searchParam.townId}

     #{searchParam.userType}
        and town_id = #{searchParam.townId}


        and (
        enterprise_name like concat('%',#{searchParam.multiParam},'%') or
        user_name like concat('%',#{searchParam.multiParam},'%') or
        id_number like concat('%',#{searchParam.multiParam},'%')
        )


        and enterprise_credit_code = #{searchParam.creditCode}


        and industry_type = #{searchParam.industryType}


        and work_type_name = #{searchParam.workType}
